SELECT EXISTS(
    SELECT 1
    FROM `user`
    WHERE status = #{status}
)

SELECT employee_id, name, email, password, role, status FROM `user`
status = #{status}
AND name LIKE CONCAT('%', #{keyword}, '%')
AND CAST(employee_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%')
ORDER BY employee_id DESC LIMIT #{size} OFFSET #{offset}

